        ST(&out_im[13*K+k],x1_im);
        ST(&out_re[21*K+k],x2_re);
        ST(&out_im[21*K+k],x2_im);
        ST(&out_re[29*K+k],x3_re);
        ST(&out_im[29*K+k],x3_im);

        /* column k1=6 */
        x0_re = _mm256_load_pd(&spill_re[6*4]);
